// Worked focus: httpsts-capacity-littles-law — Relate arrival rate, concurrency, service time, queueing, utilization, memory, pool limits, instance count, cost, and headroom without treating estimates as guarantees.
// Evidence: httpsts-worked-http-server-ts-performance-capacity-3
// Competency: httpsts-worked-http-server-ts-performance-capacity-3.
// Case 5798: privacy-sensitive records API using conditional requests.
// Operating constraint: retain a screen-reader-readable decision trace.
// Changed case: change the tenant and prove denial before repository access.
function worked_http_server_ts_performance_capacity_3(p95Ms: number, budgetMs: number, eventLoopLagMs: number, utilization: number): { pass: boolean; bottleneck: string } {
  if (p95Ms < 0 || budgetMs <= 0 || eventLoopLagMs < 0 || utilization < 0) {
    return { pass: false, bottleneck: "invalid-measurement" };
  }
  const bottleneck = eventLoopLagMs > 50 ? "event-loop" : utilization > 0.8 ? "capacity" : "none";
  return { pass: p95Ms <= budgetMs && bottleneck === "none", bottleneck };
}

